@import url('https://fonts.googleapis.com/css2?family=VT323&display=swap');

* { font-family: 'VT323', monospace !important; letter-spacing: 1px; }

body {
  background: #000 !important;
  color: #00ff9c !important;
}

/* CRT Glow */
* { text-shadow: 0 0 6px rgba(0,255,156,.6); }

/* Scanlines */
body::before {
  content: '';
  position: fixed;
  inset: 0;
  background: repeating-linear-gradient(
    0deg,
    rgba(0,0,0,.4) 0px,
    rgba(0,0,0,.4) 2px,
    transparent 2px,
    transparent 4px
  );
  pointer-events: none;
  z-index: 999999;
}

/* Remove rounded UI */
*, *::before, *::after { border-radius: 0 !important; }

/* Panels become terminal blocks */
[class*='container'],
[class*='wrapper'],
[class*='content'] {
  background: #000 !important;
  border: 1px solid #003322 !important;
}

/* Hover = phosphor brighten */
*:hover { color: #00ffcc !important; }

/* Scrollbar */
::-webkit-scrollbar { width: 10px; }
::-webkit-scrollbar-thumb { background: #00ff9c; }

@import url('https://fonts.googleapis.com/css2?family=Comfortaa:wght@400;600;700&display=swap');

:root { --font-sans: 'Comfortaa', system-ui, sans-serif; }
:root { --background-primary: #fff6f8; }
:root { --background-secondary: #fdecef; }
:root { --background-tertiary: #f7dfe5; }
:root { --brand-primary: #ff7aa2; }
:root { --text-primary: #5a2e3b; }

/* soft blossom glow */
[class*='message'] {
  background: linear-gradient(180deg, rgba(255,255,255,0.6), rgba(255,240,244,0.6));
  border-radius: 14px !important;
  box-shadow: 0 6px 18px rgba(255,122,162,0.12);
}

/* dreamy buttons */
button {
  border-radius: 999px !important;
  box-shadow: 0 4px 10px rgba(255,122,162,0.25);
}

@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;600;700&display=swap');

:root { --font-sans: 'Playfair Display', system-ui, serif; }
:root { --background-primary: #141214; }
:root { --background-secondary: #1b181b; }
:root { --background-tertiary: #0e0c0f; }
:root { --brand-primary: #d4a5ff; }
:root { --text-primary: #f5e9ff; }

/* velvet depth */
[class*='container'] {
  background: radial-gradient(circle at top, rgba(212,165,255,0.08), transparent 60%);
}

/* glass cards */
[class*='message'] {
  background: rgba(255,255,255,0.02);
  backdrop-filter: blur(6px);
  border: 1px solid rgba(212,165,255,0.15);
  border-radius: 10px !important;
}

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&display=swap');

:root { --font-sans: 'Inter', system-ui, sans-serif; }

/* frosted layout */
[class*='chat'], [class*='sidebar'] {
  background: rgba(20,24,32,0.75) !important;
  backdrop-filter: blur(12px);
}

/* glow focus */
:focus {
  outline: none !important;
  box-shadow: 0 0 0 2px rgba(122,162,255,0.6);
}

@import url('https://fonts.googleapis.com/css2?family=Roboto:wght@400;500;700&display=swap');

* { font-family: 'Roboto', system-ui, sans-serif !important; }

:root { --guildbar-height: 72px; }

/* Move guilds to top */
[class*='guildListScrollerWrapper'] {
  position: fixed !important;
  top: 0;
  left: 0;
  right: 0;
  height: var(--guildbar-height) !important;
  width: 100% !important;
  display: flex !important;
  flex-direction: row !important;
  background: #ffffff !important;
  border-bottom: 1px solid #dcdfea !important;
  z-index: 1000;
}

/* Push app below */
[class*='contentContainer'] {
  margin-top: var(--guildbar-height) !important;
}

/* Horizontal scrolling */
[class*='guildListItems'] {
  display: flex !important;
  flex-direction: row !important;
  overflow-x: auto !important;
  gap: 10px !important;
  padding: 10px !important;
}

/* Clean cards */
[class*='container'], [class*='wrapper'] {
  border-radius: 10px !important;
  box-shadow: 0 4px 14px rgba(0,0,0,.06) !important;
}

/* Modern hover */
button:hover {
  transform: translateY(-1px);
  box-shadow: 0 6px 18px rgba(0,0,0,.12);
}

