    transparent 0px, transparent 6px,
    rgba(140, 90, 60, 0.07) 6px, rgba(140, 90, 60, 0.07) 7px
  );
  pointer-events: none;
  z-index: 999999;
  animation: grainDrift 6s linear infinite;
}

