/* Candlelight — two warm shimmer bands drifting slowly top→bottom,
   like golden reflections from a candle moving across a dark ceiling.
   Slow (28s / 34s), fat glow, warm gold.
   Two bands offset by 14s so there's always warm light somewhere. */
/*@keyframes candleDrift {
  0%   { transform: translateY(-12px); opacity: 0;    }
  4%   { opacity: 0.85; }
  90%  { opacity: 0.55; }
  100% { transform: translateY(100vh); opacity: 0;    }
}
@keyframes candleDrift2 {
  0%   { transform: translateY(-8px);  opacity: 0;    }
  4%   { opacity: 0.60; }
  90%  { opacity: 0.35; }
  100% { transform: translateY(100vh); opacity: 0;    }
}*/
body::before {
  content: "";
  position: fixed; top: 0; left: 0; width: 100%; height: 10px;
  background: linear-gradient(90deg,
    transparent 0%,
    rgba(212,168,74,0.25) 20%,
    rgba(240,200,120,0.55) 40%,
    rgba(255,220,140,0.70) 55%,
    rgba(240,200,120,0.55) 70%,
    rgba(212,168,74,0.25) 85%,
    transparent 100%
  );
  box-shadow: 0 0 18px rgba(212,168,74,0.35), 0 0 40px rgba(212,168,74,0.15);
  pointer-events: none; z-index: 999999;
  animation: candleDrift 28s ease-in-out infinite;
}
body::after {
  content: "";
  position: fixed; top: 0; left: 10%; width: 80%; height: 6px;
  background: linear-gradient(90deg,
    transparent 0%,
    rgba(212,168,74,0.18) 15%,
