/* Petals — straight up, no X drift. 10 emitters across body/html/:root/app/main.
   Each has a unique duration (9s–22s) and a large spread of negative delays
   (-1s to -21s) so they never sync up and the pattern is invisible.
   Different font-sizes (8px–18px) and left% positions cover the full width. */
@keyframes petalRise {
  0%   { transform: translateY(0)      rotate(0deg);   opacity: 0; }
  6%   { opacity: 0.60; }
  100% { transform: translateY(-115vh) rotate(400deg); opacity: 0; }
}
body::before  { content:"🌸"; position:fixed; bottom:-40px; left:7%;   font-size:13px; pointer-events:none; z-index:999999; filter:drop-shadow(0 0 4px rgba(232,112,144,0.5)); animation:petalRise 11s ease-in  -3s  infinite; }
body::after   { content:"🌸"; position:fixed; bottom:-40px; left:23%;  font-size:9px;  pointer-events:none; z-index:999999; filter:drop-shadow(0 0 3px rgba(192,138,224,0.5)); animation:petalRise 17s ease-in  -9s  infinite; }
html::before  { content:"🌸"; position:fixed; bottom:-40px; left:38%;  font-size:16px; pointer-events:none; z-index:999999; filter:drop-shadow(0 0 5px rgba(232,112,144,0.4)); animation:petalRise 13s ease-in  -5s  infinite; }
html::after   { content:"🌸"; position:fixed; bottom:-40px; left:52%;  font-size:11px; pointer-events:none; z-index:999999; filter:drop-shadow(0 0 4px rgba(192,138,224,0.4)); animation:petalRise 21s ease-in  -14s infinite; }
:root::before { content:"🌸"; position:fixed; bottom:-40px; left:67%;  font-size:8px;  pointer-events:none; z-index:999999; filter:drop-shadow(0 0 3px rgba(232,112,144,0.4)); animation:petalRise 9s  ease-in  -1s  infinite; }
:root::after  { content:"🌸"; position:fixed; bottom:-40px; left:80%;  font-size:14px; pointer-events:none; z-index:999999; filter:drop-shadow(0 0 5px rgba(192,138,224,0.5)); animation:petalRise 15s ease-in  -7s  infinite; }
#app::before  { content:"🌸"; position:fixed; bottom:-40px; left:14%;  font-size:10px; pointer-events:none; z-index:999999; filter:drop-shadow(0 0 4px rgba(232,112,144,0.45)); animation:petalRise 19s ease-in  -11s infinite; }
#app::after   { content:"🌸"; position:fixed; bottom:-40px; left:44%;  font-size:17px; pointer-events:none; z-index:999999; filter:drop-shadow(0 0 6px rgba(192,138,224,0.45)); animation:petalRise 22s ease-in  -18s infinite; }
