@import url('https://fonts.googleapis.com/css2?family=Share+Tech+Mono&family=Rajdhani:wght@400;500;600;700&display=swap');
*, *::before, *::after { font-family: 'Rajdhani', system-ui, sans-serif !important; letter-spacing: 0.04em; }
code, pre, kbd, [class*="codeBlock"], [class*="markup"] code { font-family: 'Share Tech Mono', monospace !important; }

/* === SCANLINES: fixed horizontal lines across entire viewport === */
body::before {
  content: "";
  position: fixed; top: 0; left: 0; width: 100%; height: 100%;
  background: repeating-linear-gradient(
    0deg,
    transparent 0px, transparent 3px,
    rgba(0, 0, 0, 0.18) 3px, rgba(0, 0, 0, 0.18) 4px
  );
  pointer-events: none; z-index: 999999;
}

/* === STATIC BURST: full-screen noise flash, fires every ~8s, lasts ~0.3s === */
@keyframes staticBurst {
  0%,  91%           { opacity: 0; }
  92%                { opacity: 0.07; background-position: 0 0; }
  92.5%              { opacity: 0.12; background-position: -5px 3px; }
  93%                { opacity: 0.06; background-position: 2px -4px; }
  93.5%              { opacity: 0.10; background-position: -3px 1px; }
  94%, 100%          { opacity: 0; }
}
body::after {
  content: "";
  position: fixed; top: 0; left: 0; width: 100%; height: 100%;
  background-image:
    url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='1'/%3E%3C/svg%3E");
  background-size: 200px 200px;
  opacity: 0;
  pointer-events: none; z-index: 999998;
  animation: staticBurst 8s steps(1) infinite;
}

/* === RGB SPLIT on message usernames === */
@keyframes rgbSplit {
  0%,  88%           { text-shadow: none; }
  89%                { text-shadow: -2px 0 rgba(255,45,107,0.8), 2px 0 rgba(45,159,255,0.8); }
  90%                { text-shadow: 2px 0 rgba(255,45,107,0.9), -2px 0 rgba(0,255,159,0.9); }
  90.5%              { text-shadow: -1px 0 rgba(45,159,255,0.7), 1px 0 rgba(255,45,107,0.7); }
  91%, 100%          { text-shadow: none; }
}
span[class*="Message"][class*="module__messageUsername"] {
  font-weight: 700 !important;
  animation: rgbSplit 7s steps(1) infinite;
}

