/* === WATERCOLOR BLOOMS: two soft radial splotches like ink on wet paper === */
@keyframes bloomA {
  0%,100% { transform: scale(1.00) translate(0px, 0px);  opacity: 0.45; }
  40%     { transform: scale(1.18) translate(12px,-8px);  opacity: 0.30; }
  70%     { transform: scale(0.92) translate(-6px,10px);  opacity: 0.50; }
}
@keyframes bloomB {
  0%,100% { transform: scale(1.00) translate(0px, 0px);  opacity: 0.35; }
  35%     { transform: scale(1.22) translate(-14px,6px);  opacity: 0.22; }
  65%     { transform: scale(0.88) translate(8px,-12px);  opacity: 0.40; }
}
body::before {
  content: "";
  position: fixed; top: -10%; right: -5%; width: 55vw; height: 55vw;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(212,96,138,0.22) 0%, rgba(212,96,138,0.06) 55%, transparent 75%);
  pointer-events: none; z-index: 999999;
  animation: bloomA 32s ease-in-out infinite;
}
body::after {
  content: "";
  position: fixed; bottom: -8%; left: -8%; width: 60vw; height: 60vw;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(122,184,152,0.20) 0%, rgba(122,184,152,0.05) 55%, transparent 75%);
  pointer-events: none; z-index: 999998;
  animation: bloomB 41s ease-in-out 6s infinite;
}

