/* === FROST CRYSTALS: SVG snowflake-like hexagonal geometry generated via
   CSS clip-path polygon shapes. Two large faint shapes sit in opposite corners,
   slowly rotating — like ice crystals forming on glass.
   clip-path + rotate is GPU-accelerated and confirmed smooth. === */
@keyframes crystalSpin {
  from { transform: rotate(0deg);   opacity: 0.07; }
  50%  { opacity: 0.11; }
  to   { transform: rotate(360deg); opacity: 0.07; }
}
@keyframes crystalSpinR {
  from { transform: rotate(0deg);   opacity: 0.06; }
  50%  { opacity: 0.09; }
  to   { transform: rotate(-360deg); opacity: 0.06; }
}
