    rgba(26,120,200,0.60) 60deg, transparent 90deg,
    rgba(26,120,200,0.60) 120deg,transparent 150deg,
    rgba(26,120,200,0.60) 180deg,transparent 210deg,
    rgba(26,120,200,0.60) 240deg,transparent 270deg,
    rgba(26,120,200,0.60) 300deg,transparent 330deg,
