/* === OBSIDIAN SHEEN: a single diagonal highlight that very slowly drifts
   across the surface — like light catching the edge of a polished stone.
   Uses translateX on a fixed 100%-height element, narrow width, strong blur. === */
@keyframes sheenDrift {
  0%   { transform: translateX(-40vw) skewX(-18deg); opacity: 0; }
  8%   { opacity: 1; }
  92%  { opacity: 0.6; }
  100% { transform: translateX(140vw) skewX(-18deg); opacity: 0; }
}
body::before {
  content: "";
  position: fixed; top: 0; left: 0; width: 60px; height: 100%;
  background: linear-gradient(90deg,
    transparent 0%,
    rgba(255,255,255,0.025) 30%,
    rgba(255,255,255,0.055) 50%,
    rgba(255,255,255,0.025) 70%,
    transparent 100%
  );
  filter: blur(8px);
  pointer-events: none; z-index: 999999;
  animation: sheenDrift 22s ease-in-out infinite;
}

/* === CORNER ACCENT: a sharp right-angle geometric mark in top-left,
   like an architectural drawing annotation. Pure CSS borders. === */
body::after {
  content: "";
  position: fixed; top: 20px; left: 20px;
  width: 28px; height: 28px;
  border-top: 1.5px solid rgba(232,232,232,0.25);
  border-left: 1.5px solid rgba(232,232,232,0.25);
  pointer-events: none; z-index: 999998;
}
html::before {
  content: "";
  position: fixed; bottom: 20px; right: 20px;
  width: 28px; height: 28px;
  border-bottom: 1.5px solid rgba(232,232,232,0.25);
