/* === WOOD GRAIN: two sets of very subtle diagonal sine-wave-like lines
   using repeating-linear-gradient at a low angle, mimicking wood grain.
   Two layers at slightly different angles create a cross-grain pattern.
   Both static — wood grain doesn't move. === */
body::before {
  content: "";
  position: fixed; top: 0; left: 0; width: 100%; height: 100%;
  background:
    repeating-linear-gradient(
      -8deg,
      transparent 0px,        transparent 18px,
      rgba(100,55,10,0.035)  18px, rgba(100,55,10,0.035) 19px,
      transparent            19px, transparent            28px,
      rgba(100,55,10,0.020)  28px, rgba(100,55,10,0.020) 29px
    );
  pointer-events: none; z-index: 999999;
}
body::after {
  content: "";
  position: fixed; top: 0; left: 0; width: 100%; height: 100%;
  background:
    repeating-linear-gradient(
      -6deg,
      transparent 0px,        transparent 38px,
      rgba(80,40,8,0.025)   38px, rgba(80,40,8,0.025)  39px
    );
  pointer-events: none; z-index: 999998;
}

/* === WARM VIGNETTE: soft sepia burn at the edges === */
html::before {
  content: "";
  position: fixed; top: 0; left: 0; width: 100%; height: 100%;
  background: radial-gradient(
    ellipse 90% 85% at 50% 50%,
    transparent 55%,
    rgba(60,28,8,0.12) 80%,
    rgba(40,18,4,0.22) 100%
  );
  pointer-events: none; z-index: 999997;
}

