/* === RULED LINES: faint horizontal lines across the full page,
   like a composition notebook. 28px line height matches typical text.
   Single repeating-linear-gradient, very subtle (opacity 0.06 blue-grey). === */
body::before {
  content: "";
  position: fixed; top: 0; left: 0; width: 100%; height: 100%;
  background: repeating-linear-gradient(
    0deg,
    transparent 0px, transparent 27px,
    rgba(42, 74, 122, 0.07) 27px, rgba(42, 74, 122, 0.07) 28px
  );
  pointer-events: none; z-index: 999999;
}

/* === MARGIN LINE: a single vertical red line on the left, like a legal pad === */
body::after {
  content: "";
  position: fixed; top: 0; left: 68px; width: 1px; height: 100%;
  background: rgba(180, 60, 60, 0.18);
  pointer-events: none; z-index: 999998;
}

/* === INK BLEED: a soft blue-grey watercolor splotch in the top-left,
   like a pen rested on paper. Completely static — no animation. === */
html::before {
  content: "";
  position: fixed; top: -60px; left: -60px; width: 280px; height: 280px;
  border-radius: 50% 60% 55% 65%;
  background: radial-gradient(circle at 55% 55%,
    rgba(42,74,122,0.09) 0%,
    rgba(42,74,122,0.04) 45%,
    transparent 70%
  );
  pointer-events: none; z-index: 999997;
}

/* === SECOND BLEED: bottom right, faint sepia tone, like old ink fading === */
html::after {
  content: "";
  position: fixed; bottom: -80px; right: -60px; width: 320px; height: 320px;
  border-radius: 65% 50% 60% 55%;
  background: radial-gradient(circle at 45% 45%,
    rgba(122,58,40,0.07) 0%,
    rgba(122,58,40,0.03) 45%,
    transparent 68%
  );
  pointer-events: none; z-index: 999996;
}

