/* === DARK ROOM RED LIGHT: a slow radial pulse in deep crimson,
   like a single red lamp in the corner of a reading room.
   origin top-left, very large radius, very low opacity. === */
@keyframes lampBreath {
  0%,100% { opacity: 0.55; transform: scale(1.00); }
  50%     { opacity: 0.80; transform: scale(1.08); }
}
