    rgba(200,30,50,0.06) 45%,
    transparent 70%
  );
  pointer-events: none; z-index: 999999;
  animation: lampBreath 16s ease-in-out infinite;
}

/* === GOLD ACCENT GLOW: bottom-right warm gold, like candlelight from a desk lamp === */
