  border-radius: 50%;
  background: radial-gradient(circle,
    rgba(212,160,64,0.14) 0%,
    rgba(212,160,64,0.04) 50%,
    transparent 70%
  );
  pointer-events: none; z-index: 999998;
  animation: lampBreath 22s ease-in-out 6s infinite;
}

