@keyframes pulseA {
  0%,100% { transform: scale(1.00) translate(0,0);     opacity: 0.55; }
  30%     { transform: scale(1.20) translate(20px,-10px); opacity: 0.85; }
  60%     { transform: scale(0.90) translate(-10px,15px); opacity: 0.40; }
}
@keyframes pulseB {
  0%,100% { transform: scale(1.00) translate(0,0);     opacity: 0.45; }
  40%     { transform: scale(1.25) translate(-15px,8px); opacity: 0.75; }
  70%     { transform: scale(0.85) translate(12px,-18px); opacity: 0.35; }
}
@keyframes pulseC {
  0%,100% { transform: scale(1.00) translate(0,0);     opacity: 0.35; }
  50%     { transform: scale(1.15) translate(8px,12px);  opacity: 0.60; }
}
body::before {
  content: "";
  position: fixed; top: 10%; left: 5%;
  width: 45vw; height: 45vw;
  border-radius: 50%;
  background: radial-gradient(circle,
    rgba(0,232,200,0.22) 0%,
    rgba(0,200,180,0.06) 50%,
    transparent 72%
  );
  pointer-events: none; z-index: 999999;
  animation: pulseA 11s ease-in-out infinite;
}
body::after {
  content: "";
  position: fixed; bottom: 5%; right: 8%;
  width: 40vw; height: 40vw;
  border-radius: 50%;
  background: radial-gradient(circle,
    rgba(128,64,248,0.20) 0%,
    rgba(100,40,220,0.05) 50%,
    transparent 70%
  );
  pointer-events: none; z-index: 999998;
  animation: pulseB 15s ease-in-out 3s infinite;
}
html::before {
  content: "";
  position: fixed; top: 50%; right: 20%;
  width: 30vw; height: 30vw;
  border-radius: 50%;
  background: radial-gradient(circle,
    rgba(64,184,255,0.16) 0%,
    rgba(40,160,240,0.04) 50%,
    transparent 70%
  );
  pointer-events: none; z-index: 999997;
  animation: pulseC 19s ease-in-out 7s infinite;
}

/* === PARTICLE SPARKLES: tiny bright dots, box-shadow trick === */
html::after {
  content: "";
  position: fixed; top: 0; left: 0; width: 1px; height: 1px;
  background: transparent;
  pointer-events: none; z-index: 999996;
  box-shadow:
    15vw 20vh 2px 0 rgba(0,232,200,0.60),  44vw 12vh 1px 0 rgba(128,64,248,0.55),
    72vw 35vh 2px 0 rgba(0,232,200,0.50),  28vw 60vh 1px 0 rgba(64,184,255,0.60),
    85vw 18vh 2px 0 rgba(128,64,248,0.45), 8vw  78vh 1px 0 rgba(0,232,200,0.55),
    56vw 70vh 2px 0 rgba(64,184,255,0.50), 91vw 55vh 1px 0 rgba(0,232,200,0.40),
    33vw 88vh 2px 0 rgba(128,64,248,0.50), 67vw 82vh 1px 0 rgba(64,184,255,0.45);
}

