@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400;1,700&family=IM+Fell+English:ital@0;1&display=swap');
*, *::before, *::after { font-family: 'IM Fell English', Georgia, serif !important; letter-spacing: 0.015em; }
[class*="username"], [class*="Username"], [class*="channelName"], [class*="guildName"], h1, h2, h3 { font-family: 'Playfair Display', Georgia, serif !important; font-weight: 700 !important; }
code, pre, kbd, [class*="codeBlock"], [class*="markup"] code { font-family: 'Courier New', monospace !important; }

/* === AGED PAPER TEXTURE: crosshatch of two diagonal line sets at opposing angles,
   combined with a very slight warm tint gradient across the page.
   Mimics the surface texture of old parchment. === */
body::before {
  content: "";
  position: fixed; top: 0; left: 0; width: 100%; height: 100%;
  background:
    repeating-linear-gradient(
      45deg,
      transparent 0px, transparent 12px,
      rgba(100,70,20,0.028) 12px, rgba(100,70,20,0.028) 13px
    ),
    repeating-linear-gradient(
      -45deg,
      transparent 0px, transparent 18px,
      rgba(80,50,10,0.018) 18px, rgba(80,50,10,0.018) 19px
    );
  pointer-events: none; z-index: 999999;
}

/* === FOXING: scattered warm amber splotches, like aged paper spots.
   Two static blobs, one per corner, very faint. === */
body::after {
  content: "";
  position: fixed; top: -8%; right: -5%;
  width: 35vw; height: 35vw; border-radius: 50%;
  background: radial-gradient(circle,
    rgba(160,100,40,0.08) 0%,
    rgba(140,80,20,0.02) 55%,
    transparent 75%
  );
  pointer-events: none; z-index: 999998;
}
html::before {
  content: "";
  position: fixed; bottom: -5%; left: -5%;
  width: 28vw; height: 28vw; border-radius: 50%;
  background: radial-gradient(circle,
    rgba(140,80,30,0.07) 0%,
    rgba(120,60,10,0.02) 55%,
    transparent 75%
  );
  pointer-events: none; z-index: 999997;
}

